 27	  describe('Rendering', () => {
 28	    test('renders with default placeholder', () => {
 29	      render(<TypeaheadSelect {...defaultProps} />);
 30	
 31	      const input = screen.getByRole('combobox');
 32	      expect(input).toBeInTheDocument();
 33	      expect(input).toHaveAttribute('placeholder', 'Select an option');
 34	    });
 35	
 36	    test('renders with custom placeholder when provided', () => {
 37	      const customPlaceholder = 'Choose an item';
 38	      render(<TypeaheadSelect {...defaultProps} placeholder={customPlaceholder} />);
 39	
 40	      const input = screen.getByRole('combobox');
 41	      expect(input).toHaveAttribute('placeholder', customPlaceholder);
 42	    });
 43	
 44	    test('renders with initial value', () => {
 45	      render(<TypeaheadSelect {...defaultProps} value="option2" />);
 46	
 47	      const input = screen.getByRole('combobox');
 48	      expect(input).toHaveValue('Option 2');
 49	    });
 50	
 51	    test('renders as disabled when isDisabled is true', async () => {
 52	      const user = userEvent.setup();
 53	      render(<TypeaheadSelect {...defaultProps} isDisabled />);
 54	
 55	      const input = screen.getByRole('combobox');
 56	      const toggleButton = screen.getByRole('button', { name: /menu toggle/i });
 57	
 58	      // Verify that clicking doesn't open the dropdown (functional disabled behavior)
 59	      await user.click(input);
 60	      expect(input).toHaveAttribute('aria-expanded', 'false');
 61	
 62	      await user.click(toggleButton);
 63	      expect(input).toHaveAttribute('aria-expanded', 'false');
 64	
 65	      // Verify no options are shown (because dropdown didn't open)
 66	      expect(screen.queryByText('Option 1')).not.toBeInTheDocument();
 67	    });
 68	  });
 69	
 70	  describe('User Interactions', () => {
 71	    test('opens dropdown when input is clicked', async () => {
 72	      const user = userEvent.setup();
 73	      render(<TypeaheadSelect {...defaultProps} />);
 74	
 75	      const input = screen.getByRole('combobox');
 76	      expect(input).toHaveAttribute('aria-expanded', 'false');
 77	
 78	      await user.click(input);
 79	
 80	      expect(input).toHaveAttribute('aria-expanded', 'true');
 81	      expect(screen.getByText('Option 1')).toBeInTheDocument();
 82	      expect(screen.getByText('Option 2')).toBeInTheDocument();
 83	      expect(screen.getByText('Option 3')).toBeInTheDocument();
 84	    });
 85	
 86	    test('selects an option when clicked', async () => {
 87	      const user = userEvent.setup();
 88	      render(<TypeaheadSelect {...defaultProps} />);
 89	
 90	      const input = screen.getByRole('combobox');
 91	      await user.click(input);
 92	
 93	      await waitFor(() => {
 94	        expect(screen.getByText('Option 1')).toBeInTheDocument();
 95	      });
 96	
 97	      await user.click(screen.getByText('Option 2'));
 98	
 99	      expect(mockOnChange).toHaveBeenCalledWith('option2');
100	      expect(input).toHaveAttribute('aria-expanded', 'false');
101	    });
102	
103	    test('does not open dropdown when disabled', async () => {
104	      const user = userEvent.setup();
105	      render(<TypeaheadSelect {...defaultProps} isDisabled />);
106	
107	      const input = screen.getByRole('combobox');
108	      await user.click(input);
109	
110	      expect(screen.queryByText('Option 1')).not.toBeInTheDocument();
111	      expect(mockOnChange).not.toHaveBeenCalled();
112	    });
113	  });
114	
115	  describe('Selection Clearing', () => {
116	    test('shows clear button when allowClear is true and value is selected', async () => {
117	      const user = userEvent.setup();
118	      render(<TypeaheadSelect {...defaultProps} value="option2" allowClear />);
119	
120	      const input = screen.getByRole('combobox');
121	      expect(input).toHaveValue('Option 2');
122	
123	      // Focus input to make clear button appear
124	      await user.click(input);
125	
126	      const clearButton = screen.getByRole('button', { name: /clear/i });
127	      expect(clearButton).toBeInTheDocument();
128	    });
129	
130	    test('clears selected value when clear button is clicked', async () => {
131	      const user = userEvent.setup();
132	      render(<TypeaheadSelect {...defaultProps} value="option2" allowClear />);
133	
134	      const input = screen.getByRole('combobox');
135	      await user.click(input);
136	
137	      const clearButton = screen.getByRole('button', { name: /clear/i });
138	      await user.click(clearButton);
139	
140	      expect(mockOnChange).toHaveBeenCalledWith('');
141	    });
142	
143	    test('handles select, clear, and select workflow', async () => {
144	      const user = userEvent.setup();
145	      const { rerender } = render(<TypeaheadSelect {...defaultProps} allowClear />);
146	
147	      const input = screen.getByRole('combobox');
148	
149	      // Select first option
150	      await user.click(input);
151	      await user.click(screen.getByText('Option 1'));
152	      expect(mockOnChange).toHaveBeenCalledWith('option1');
153	
154	      // Re-render with selected value
155	      rerender(<TypeaheadSelect {...defaultProps} value="option1" allowClear />);
156	
157	      // Clear the selection
158	      await user.click(input);
159	      const clearButton = screen.getByRole('button', { name: /clear/i });
160	      await user.click(clearButton);
161	      expect(mockOnChange).toHaveBeenCalledWith('');
162	
163	      // Re-render cleared state
164	      rerender(<TypeaheadSelect {...defaultProps} allowClear />);
165	
166	      // Select different option
167	      await user.click(input);
168	      await user.click(screen.getByText('Option 3'));
169	      expect(mockOnChange).toHaveBeenCalledWith('option3');
170	    });
171	
172	    test('clears selection when input is manually cleared', async () => {
173	      const user = userEvent.setup();
174	      render(<TypeaheadSelect {...defaultProps} value="option1" />);
175	
176	      const input = screen.getByRole('combobox');
177	      expect(input).toHaveValue('Option 1');
178	
179	      await user.click(input);
180	      await user.clear(input);
181	
182	      expect(mockOnChange).toHaveBeenCalledWith('');
183	    });
184	  });
185	
186	  describe('Filtering', () => {
187	    test('filters options as user types', async () => {
188	      const user = userEvent.setup();
189	      render(<TypeaheadSelect {...defaultProps} />);
190	
191	      const input = screen.getByRole('combobox');
192	      await user.click(input);
193	      await user.type(input, '1');
194	
195	      await waitFor(() => {
196	        expect(screen.getByText('Option 1')).toBeInTheDocument();
197	        expect(screen.queryByText('Option 2')).not.toBeInTheDocument();
198	        expect(screen.queryByText('Option 3')).not.toBeInTheDocument();
199	      });
200	    });
201	
202	    test('performs case insensitive filtering', async () => {
203	      const user = userEvent.setup();
204	      render(<TypeaheadSelect {...defaultProps} />);
205	
206	      const input = screen.getByRole('combobox');
207	      await user.click(input);
208	      await user.type(input, 'OPTION 1');
209	
210	      await waitFor(() => {
211	        expect(screen.getByText('Option 1')).toBeInTheDocument();
212	        expect(screen.queryByText('Option 2')).not.toBeInTheDocument();
213	        expect(screen.queryByText('Option 3')).not.toBeInTheDocument();
214	      });
215	    });
216	
217	    test('applies custom filter function when provided', async () => {
218	      const user = userEvent.setup();
219	      const customFilter = (filterValue: string, options: TypeaheadSelectOption[]) =>
220	        options.filter((option) => String(option.value).includes(filterValue));
221	
222	      render(<TypeaheadSelect {...defaultProps} filterFunction={customFilter} />);
223	
224	      const input = screen.getByRole('combobox');
225	      await user.click(input);
226	      await user.type(input, '2');
227	
228	      await waitFor(() => {
229	        expect(screen.getByText('Option 2')).toBeInTheDocument();
230	        expect(screen.queryByText('Option 1')).not.toBeInTheDocument();
231	        expect(screen.queryByText('Option 3')).not.toBeInTheDocument();
232	      });
233	    });
234	
235	    test('calls onInputChange when input value changes', async () => {
236	      const user = userEvent.setup();
237	      render(<TypeaheadSelect {...defaultProps} onInputChange={mockOnInputChange} />);
238	
239	      const input = screen.getByRole('combobox');
240	      await user.click(input);
241	      await user.type(input, 'test');
242	
243	      expect(mockOnInputChange).toHaveBeenCalledWith('test');
244	    });
245	  });
246	
247	  describe('Creatable Options', () => {
248	    test('creates new option when isCreatable is true', async () => {
249	      const user = userEvent.setup();
250	      render(<TypeaheadSelect {...defaultProps} isCreatable />);
251	
252	      const input = screen.getByRole('combobox');
253	      await user.click(input);
254	      await user.type(input, 'New Option');
255	
256	      await waitFor(() => {
257	        expect(screen.getByText('Create "New Option"')).toBeInTheDocument();
258	      });
259	
260	      await user.click(screen.getByText('Create "New Option"'));
261	
262	      expect(mockOnChange).toHaveBeenCalledWith('New Option');
263	      expect(input).toHaveAttribute('aria-expanded', 'false');
264	    });
265	
266	    test('shows custom create option message when provided', async () => {
267	      const user = userEvent.setup();
268	      const customMessage = (value: string) => `Add new: ${value}`;
269	      render(<TypeaheadSelect {...defaultProps} isCreatable createOptionMessage={customMessage} />);
270	
271	      const input = screen.getByRole('combobox');
272	      await user.click(input);
273	      await user.type(input, 'Custom Item');
274	
275	      await waitFor(() => {
276	        expect(screen.getByText('Add new: Custom Item')).toBeInTheDocument();
277	      });
278	    });
279	
280	    test('prevents creating duplicate options', async () => {
281	      const user = userEvent.setup();
282	      render(<TypeaheadSelect {...defaultProps} isCreatable />);
283	
284	      const input = screen.getByRole('combobox');
285	      await user.click(input);
286	      await user.type(input, 'Option 1');
287	
288	      await waitFor(() => {
289	        expect(screen.getByText('Option 1')).toBeInTheDocument();
290	        expect(screen.queryByText('Create "Option 1"')).not.toBeInTheDocument();
291	      });
292	    });
293	  });
294	
295	  describe('No Options/Results Messages', () => {
296	    test('shows custom no options message when no options are provided', async () => {
297	      const user = userEvent.setup();
298	      const customMessage = 'Custom no options message';
299	      render(
300	        <TypeaheadSelect options={[]} onChange={mockOnChange} noOptionsMessage={customMessage} />,
301	      );
302	
303	      const input = screen.getByRole('combobox');
304	      await user.click(input);
305	
306	      await waitFor(() => {
307	        expect(screen.getByText(customMessage)).toBeInTheDocument();
308	      });
309	    });
310	
311	    test('shows custom no results message when filtering returns no results', async () => {
312	      const user = userEvent.setup();
313	      const customMessage = (filter: string) => `Custom no results for "${filter}"`;
314	      render(<TypeaheadSelect {...defaultProps} noResultsMessage={customMessage} />);
315	
316	      const input = screen.getByRole('combobox');
317	      await user.click(input);
318	      await user.type(input, 'nonexistent');
319	
320	      await waitFor(() => {
321	        expect(screen.getByText('Custom no results for "nonexistent"')).toBeInTheDocument();
322	      });
323	    });
324	  });
325	
326	  describe('Keyboard Navigation', () => {
327	    test('selects option with Enter key', async () => {
328	      const user = userEvent.setup();
329	      render(<TypeaheadSelect {...defaultProps} />);
330	
331	      const input = screen.getByRole('combobox');
332	      await user.click(input);
333	
334	      // Navigate to second option and press Enter
335	      await user.keyboard('{ArrowDown}{ArrowDown}{Enter}');
336	
337	      expect(mockOnChange).toHaveBeenCalledWith('option2');
338	    });
339	
340	    test('closes dropdown with Escape key', async () => {
341	      const user = userEvent.setup();
342	      render(<TypeaheadSelect {...defaultProps} />);
343	
344	      const input = screen.getByRole('combobox');
345	      await user.click(input);
346	
347	      // Verify dropdown is open
348	      expect(input).toHaveAttribute('aria-expanded', 'true');
349	
350	      await user.keyboard('{Escape}');
351	
352	      // Verify dropdown is closed
353	      await waitFor(() => {
354	        expect(input).toHaveAttribute('aria-expanded', 'false');
355	      });
356	    });
357	  });
358	
359	  describe('Toggle Button', () => {
360	    test('opens and closes dropdown when toggle button is clicked', async () => {
361	      const user = userEvent.setup();
362	      render(<TypeaheadSelect {...defaultProps} />);
363	
364	      const input = screen.getByRole('combobox');
365	      const toggleButton = screen.getByRole('button', { name: /menu toggle/i });
366	
367	      // Initially closed
368	      expect(input).toHaveAttribute('aria-expanded', 'false');
369	
370	      // Click toggle to open
371	      await user.click(toggleButton);
372	      expect(input).toHaveAttribute('aria-expanded', 'true');
373	
374	      // Click toggle to close
375	      await user.click(toggleButton);
376	      await waitFor(() => {
377	        expect(input).toHaveAttribute('aria-expanded', 'false');
378	      });
379	    });
380	  });
381	});

