269	      render(<TypeaheadSelect {...defaultProps} isCreatable createOptionMessage={customMessage} />);
270	
271	      const input = screen.getByRole('combobox');
272	      await user.click(input);
273	      await user.type(input, 'Custom Item');
274	
275	      await waitFor(() => {
276	        expect(screen.getByText('Add new: Custom Item')).toBeInTheDocument();
277	      });
278	    });
279	
280	    test('prevents creating duplicate options', async () => {
281	      const user = userEvent.setup();
282	      render(<TypeaheadSelect {...defaultProps} isCreatable />);
283	
284	      const input = screen.getByRole('combobox');
285	      await user.click(input);
