  1	import { type FC, type FormEvent, type Ref, type RefObject, useState } from 'react';
  2	
  3	import {
  4	  Button,
  5	  ButtonVariant,
  6	  MenuToggle,
  7	  type MenuToggleElement,
  8	  type MenuToggleProps,
  9	  TextInputGroup,
 10	  TextInputGroupMain,
 11	  TextInputGroupUtilities,
 12	} from '@patternfly/react-core';
 13	import { TimesIcon } from '@patternfly/react-icons';
 14	
 15	import type { TypeaheadSelectOption } from './utils/types';
 16	
 17	type TypeaheadMenuToggleProps = {
 18	  toggleRef: Ref<MenuToggleElement>;
 19	  inputRef: RefObject<HTMLInputElement>;
 20	  placeholder: string;
 21	  isDisabled: boolean;
 22	  isOpen: boolean;
 23	  toggleWidth?: string;
 24	  allowClear: boolean;
 25	  selectedOption?: TypeaheadSelectOption;
 26	  isFiltering: boolean;
 27	  inputValue: string;
 28	  onInputChange?: (value: string) => void;
 29	  onSelectionClear: () => void;
 30	  onToggleClick: () => void;
 31	  onInputValueChange: (value: string, isFiltering: boolean) => void;
 32	  toggleProps?: Omit<MenuToggleProps, 'ref' | 'onClick' | 'isExpanded'>;
 33	  testId?: string;
 34	};
 35	
 36	const TypeaheadMenuToggle: FC<TypeaheadMenuToggleProps> = ({
 37	  allowClear,
 38	  inputRef,
 39	  inputValue,
 40	  isDisabled,
 41	  isFiltering,
 42	  isOpen,
 43	  onInputChange,
 44	  onInputValueChange,
 45	  onSelectionClear,
 46	  onToggleClick,
 47	  placeholder,
 48	  selectedOption,
 49	  testId,
 50	  toggleProps,
 51	  toggleRef,
 52	  toggleWidth,
 53	}) => {
 54	  const [isFocused, setIsFocused] = useState(false);
 55	  const [isHovered, setIsHovered] = useState(false);
 56	
 57	  // Derive the display value: use input value when filtering, selected option content when not
 58	  const displayValue = isFiltering ? inputValue : (selectedOption?.content?.toString() ?? '');
 59	
 60	  const handleToggleClick = (): void => {
 61	    if (isDisabled) return;
 62	    onToggleClick();
 63	
 64	    if (!isOpen) {
 65	      setTimeout(() => inputRef.current?.focus(), 0);
 66	    }
 67	  };
 68	
 69	  const handleInputChange = (event: FormEvent<HTMLInputElement>, newValue: string): void => {
 70	    onInputValueChange(newValue, true);
 71	    onInputChange?.(newValue);
 72	
 73	    // If user clears input, clear the selection
 74	    if (newValue === '' && selectedOption) {
 75	      onSelectionClear();
 76	    }
 77	
 78	    // Open dropdown when user starts typing
 79	    if (!isOpen && newValue.length > 0) {
 80	      onToggleClick();
 81	    }
 82	  };
 83	
 84	  const handleClear = (): void => {
 85	    onInputValueChange('', false);
 86	    onSelectionClear();
 87	    inputRef.current?.focus();
 88	  };
 89	
 90	  const handleInputClick = (): void => {
 91	    if (!isOpen && !isDisabled) {
 92	      onToggleClick();
 93	    }
 94	  };
 95	
 96	  // Show clear button when there's a value to clear AND (focused, hovered, or actively filtering)
 97	  const hasValueToClear = selectedOption ?? (isFiltering && inputValue);
 98	  const showClearButton = allowClear && hasValueToClear && (isFocused || isHovered || isFiltering);
 99	
100	  return (
101	    <MenuToggle
102	      ref={toggleRef}
103	      variant="typeahead"
104	      onClick={handleToggleClick}
105	      isExpanded={isOpen}
106	      isDisabled={isDisabled}
107	      isFullWidth
108	      style={{ width: toggleWidth }}
109	      onMouseEnter={() => {
110	        setIsHovered(true);
111	      }}
112	      onMouseLeave={() => {
113	        setIsHovered(false);
114	      }}
115	      data-testid={testId}
116	      {...toggleProps}
117	    >
118	      <TextInputGroup isPlain>
119	        <TextInputGroupMain
120	          value={displayValue}
121	          onClick={handleInputClick}
122	          onChange={handleInputChange}
123	          onFocus={() => {
124	            setIsFocused(true);
125	          }}
126	          onBlur={() => {
127	            setIsFocused(false);
128	          }}
129	          autoComplete="off"
130	          ref={inputRef}
131	          placeholder={placeholder}
132	          role="combobox"
133	          isExpanded={isOpen}
134	          aria-controls="typeahead-listbox"
135	        />
136	        {showClearButton && (
137	          <TextInputGroupUtilities>
138	            <Button
139	              icon={<TimesIcon />}
140	              variant={ButtonVariant.plain}
141	              onClick={handleClear}
142	              aria-label="Clear selection"
143	            />
144	          </TextInputGroupUtilities>
145	        )}
146	      </TextInputGroup>
147	    </MenuToggle>
148	  );
149	};
150	
151	export default TypeaheadMenuToggle;

